import os
import sys
import shutil
import subprocess
import hashlib
import zipfile
from pathlib import Path

ROOT = Path(__file__).resolve().parent
REQ = ROOT / "requirements.txt"
DIST = ROOT / "dist"
BUILD = ROOT / "build"
ARTIFACT = DIST / "deployment_package.zip"


def run(cmd, cwd=ROOT, env=None):
    print("+", " ".join(cmd))
    subprocess.run(cmd, cwd=str(cwd), env=env, check=True)


def sha256_file(path: Path) -> str:
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def ensure_dirs():
    DIST.mkdir(parents=True, exist_ok=True)
    BUILD.mkdir(parents=True, exist_ok=True)


def clean():
    for p in (DIST, BUILD):
        if p.exists():
            shutil.rmtree(p)
    ensure_dirs()


def install_deps():
    if not REQ.exists():
        print(f"requirements.txt not found at: {REQ}", file=sys.stderr)
        sys.exit(2)

    run([sys.executable, "-m", "pip", "install", "--upgrade", "pip", "setuptools", "wheel"])
    run([sys.executable, "-m", "pip", "install", "-r", str(REQ)])


def run_tests():
    # Prefer pytest if available; otherwise fall back to unittest discovery.
    try:
        run([sys.executable, "-m", "pytest", "-q"])
    except subprocess.CalledProcessError:
        raise
    except Exception:
        run([sys.executable, "-m", "unittest", "discover", "-v"])


def should_exclude(path: Path) -> bool:
    parts = set(path.parts)
    if any(p.startswith(".") for p in path.parts):
        return True
    if "__pycache__" in parts:
        return True
    if any(p.endswith((".pyc", ".pyo")) for p in path.parts):
        return True
    if "dist" in parts or "build" in parts:
        return True
    if ".venv" in parts or "venv" in parts:
        return True
    if ".git" in parts:
        return True
    if ".pytest_cache" in parts:
        return True
    if ".mypy_cache" in parts:
        return True
    if ".tox" in parts:
        return True
    if "node_modules" in parts:
        return True
    return False


def package():
    ensure_dirs()
    if ARTIFACT.exists():
        ARTIFACT.unlink()

    with zipfile.ZipFile(ARTIFACT, "w", compression=zipfile.ZIP_DEFLATED, compresslevel=6) as zf:
        for p in ROOT.rglob("*"):
            if p.is_dir():
                continue
            if should_exclude(p.relative_to(ROOT)):
                continue
            arcname = str(p.relative_to(ROOT)).replace("\\", "/")
            zf.write(p, arcname)

    digest = sha256_file(ARTIFACT)
    (DIST / "deployment_package.sha256").write_text(f"{digest}  {ARTIFACT.name}\n", encoding="utf-8")
    print(f"Artifact: {ARTIFACT}")
    print(f"SHA256:   {digest}")


def main():
    cmd = (sys.argv[1] if len(sys.argv) > 1 else "all").lower()

    if cmd in ("clean",):
        clean()
        return

    if cmd in ("deps", "install"):
        install_deps()
        return

    if cmd in ("test", "tests"):
        run_tests()
        return

    if cmd in ("package", "pack"):
        package()
        return

    if cmd in ("all", "ci"):
        install_deps()
        run_tests()
        package()
        return

    print("Usage: python deploy.py [clean|deps|test|package|all]", file=sys.stderr)
    sys.exit(2)


if __name__ == "__main__":
    main()